const fs = require('fs');

function readJson(path) {
  if (!fs.existsSync(path)) return {};
  return JSON.parse(fs.readFileSync(path, 'utf8'));
}

const workflowConfigPath = '/files/config/tiktok_zernio.json';
const captionConfigPath = '/files/config/caption_ai.json';
const workflowConfig = readJson(workflowConfigPath);
const captionConfig = readJson(captionConfigPath);
const folderId = String(workflowConfig.manual_drive_inbox_folder_id || '').trim();
const placeholder = folderId.startsWith('ISI_DENGAN_');
const configError = !folderId || placeholder
  ? 'Isi manual_drive_inbox_folder_id di /files/config/tiktok_zernio.json sebelum mengaktifkan WF-05.'
  : '';

return {
  json: {
    config_ready: !configError,
    config_error: configError,
    manual_drive_inbox_folder_id: folderId,
    zernio_tiktok_account_id: String(workflowConfig.zernio_tiktok_account_id || '').trim(),
    default_content_context: String(workflowConfig.default_content_context || '').trim(),
    openai_api_key: String(captionConfig.openai_api_key || $env.OPENAI_API_KEY || '').trim(),
    openai_caption_model: String(captionConfig.openai_caption_model || $env.OPENAI_CAPTION_MODEL || 'gpt-5.4-mini'),
    openai_caption_language: String(captionConfig.openai_caption_language || $env.OPENAI_CAPTION_LANGUAGE || 'id'),
    openai_caption_brand_voice: String(captionConfig.openai_caption_brand_voice || $env.OPENAI_CAPTION_BRAND_VOICE || 'ringkas, tajam, natural, tidak clickbait murahan'),
    openai_caption_max_hashtags: Number.parseInt(String(captionConfig.openai_caption_max_hashtags || $env.OPENAI_CAPTION_MAX_HASHTAGS || '8'), 10),
  }
};

const fs = require('fs');
const path = require('path');
const config = $('Load WF05 Config').first().json;
const statePath = '/files/state/wf05_manual_gdrive_processed.json';
let state = { processed: {} };

if (fs.existsSync(statePath)) {
  try {
    state = JSON.parse(fs.readFileSync(statePath, 'utf8'));
  } catch (error) {
    throw new Error('State WF-05 rusak: ' + error.message);
  }
}
if (!state.processed || typeof state.processed !== 'object') state.processed = {};

// Clean up stale in_progress entries older than 30 minutes
const staleCutoff = Date.now() - (30 * 60 * 1000);
for (const [key, val] of Object.entries(state.processed)) {
  if (val.status === 'IN_PROGRESS' && val.picked_at) {
    const ts = Date.parse(val.picked_at);
    if (Number.isFinite(ts) && ts < staleCutoff) {
      delete state.processed[key];
    }
  }
}

const files = Array.isArray($json.files) ? $json.files : [];
const output = [];
const pickedAt = new Date().toISOString();
const tempState = { ...state };

for (const file of files) {
  const previous = tempState.processed[file.id];
  // Skip if already completed or currently being processed
  if (previous && (previous.status === 'TIKTOK_DRAFT_CREATED' || previous.status === 'IN_PROGRESS')) {
    continue;
  }
  if (String(file.mimeType || '').toLowerCase() !== 'video/mp4') continue;

  // Mark as in_progress immediately to prevent concurrent runs from picking it up
  tempState.processed[file.id] = {
    status: 'IN_PROGRESS',
    picked_at: pickedAt,
    gdrive_file_id: file.id,
    gdrive_file_name: file.name || '',
  };

  output.push({
    json: {
      ...config,
      gdrive_file_id: file.id,
      gdrive_file_name: file.name || '',
      gdrive_mime_type: file.mimeType || '',
      gdrive_description: file.description || '',
      gdrive_created_time: file.createdTime || '',
      gdrive_web_view_link: file.webViewLink || '',
      gdrive_size: file.size || '',
      state_path: statePath,
    }
  });
}

// Write updated state file with in_progress markers
if (output.length > 0) {
  const tmpPath = statePath + '.tmp.' + process.pid;
  fs.writeFileSync(tmpPath, JSON.stringify(tempState, null, 2) + '\n', 'utf8');
  fs.renameSync(tmpPath, statePath);
}

if (output.length === 0) {
  return [{ json: { status: 'NOTHING_TO_UPLOAD' } }];
}
return output;

const apiKey = String($json.openai_api_key || '').trim();
const model = String($json.openai_caption_model || 'gpt-5.4-mini');
const language = String($json.openai_caption_language || 'id');
const brandVoice = String($json.openai_caption_brand_voice || 'ringkas, tajam, natural, tidak clickbait murahan');
const maxHashtags = Number.isFinite($json.openai_caption_max_hashtags) ? $json.openai_caption_max_hashtags : 8;

function failure(message) {
  return { json: { ...$json, caption_generation_status: 'failed', caption_error: message } };
}
if (!apiKey) return failure('OpenAI API key belum tersedia di /files/config/caption_ai.json atau OPENAI_API_KEY.');

const schema = {
  type: 'object',
  additionalProperties: false,
  properties: {
    content_angle: { type: 'string' },
    caption: { type: 'string' },
    hashtags: { type: 'array', items: { type: 'string' } }
  },
  required: ['content_angle', 'caption', 'hashtags']
};

const transcriptText = String($json.transcript_text || '').trim();
const transcriptAvailable = transcriptText.length > 0;
const fileName = String($json.gdrive_file_name || '').trim();
const contentContext = String($json.default_content_context || '').trim();

const context = {
  language,
  brand_voice: brandVoice,
  max_hashtags: maxHashtags,
  platform: 'tiktok',
  file_name: fileName,
  transcript_available: transcriptAvailable,
  transcript_text: transcriptAvailable ? transcriptText.slice(0, 6000) : null,
  content_context: contentContext || null,
};

const systemPrompt = 'Anda adalah copywriter TikTok yang kreatif dan spesifik. Balas hanya JSON valid sesuai schema. SUMBER KONTEN UTAMA: Gunakan transcript_text untuk memahami isi video dan buat caption yang spesifik membahas topik di transcript. Jika transcript tersedia, caption WAJIB relevan dengan isi transcript, bukan umum. Jika transcript TIDAK tersedia, gunakan content_context atau file_name sebagai referensi, dan buat caption yang jujur serta mengajak audience menonton. JANGAN PERNAH buat caption generik seperti "Kadang yang simpel justru paling kena", "Simple, padat, langsung ke inti", atau "Simpan kalau relate" karena itu tidak spesifik dan membosankan. Caption harus membuat orang penasaran atau merasa langsung terhubung dengan topik spesifik dari video. content_angle harus berisi ringkasan pendek tentang sudut pandang konten, BUKAN parafrase caption. PENTING UNTUK VARIASI: Caption HARUS unik. Gunakan berbagai gaya: pertanyaan pembuka, pernyataan tegas, storytelling singkat, fakta mengejutkan, atau opini berani. Variasikan panjang dan ritme caption. UNTUK HASHTAG: JANGAN pernah pakai hashtag generik seperti #fyp, #foryou, #foryoupage, #tiktok, #viral, #tiktokindonesia, #tiktokviral, #fypシ, #xyzbca. Hashtag WAJIB spesifik dari isi konten/transcript. Jika tidak ada konteks cukup, gunakan hashtag minimal yang relevan.';

const body = {
  model,
  store: false,
  input: [
    {
      role: 'system',
      content: [{ type: 'input_text', text: systemPrompt }]
    },
    { role: 'user', content: [{ type: 'input_text', text: JSON.stringify(context, null, 2) }] }
  ],
  temperature: 0.85,
  text: { format: { type: 'json_schema', name: 'manual_drive_tiktok_caption', strict: true, schema } }
};

try {
  const data = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/responses',
    headers: { 'Content-Type': 'application/json', Authorization: 'Bearer ' + apiKey },
    body,
    json: true,
  });
  let parsed = data.output_parsed || null;
  let outputText = data.output_text || '';
  if (!parsed && !outputText && Array.isArray(data.output)) {
    for (const item of data.output) {
      for (const part of item.content || []) {
        if (typeof part.text === 'string' && part.text.trim()) outputText = part.text;
      }
    }
  }
  if (!parsed) parsed = JSON.parse(outputText);
  const hashtags = (Array.isArray(parsed.hashtags) ? parsed.hashtags : [])
    .map((tag) => String(tag || '').trim())
    .filter(Boolean)
    .map((tag) => tag.startsWith('#') ? tag : '#' + tag)
    .map((tag) => tag.toLowerCase())
    .slice(0, maxHashtags);
  const caption = String(parsed.caption || '').trim();
  return {
    json: {
      ...$json,
      caption_generation_status: 'generated',
      caption_model: model,
      content_angle: String(parsed.content_angle || '').trim(),
      caption,
      hashtags,
      caption_full: [caption, hashtags.join(' ')].filter(Boolean).join(' ').trim(),
    }
  };
} catch (error) {
  return failure(error.message || 'Gagal membuat caption melalui OpenAI.');
}

const fs = require('fs');
const path = require('path');
const captionItems = $('Generate TikTok Caption').all();
const output = [];
const apiKey = fs.readFileSync('/files/config/zernio_api_key.txt', 'utf8').trim();

for (const item of captionItems) {
  const original = item.json;
  if (original.caption_generation_status !== 'generated') continue;
  const fileId = String(original.gdrive_file_id || '').trim();
  const accountId = String(original.zernio_tiktok_account_id || '').trim();
  if (!fileId) throw new Error('Google Drive file ID kosong.');
  if (!accountId) throw new Error('zernio_tiktok_account_id belum diisi di config WF-05.');
  const videoUrl = 'https://drive.google.com/uc?export=download&id=' + fileId;
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://zernio.com/api/v1/posts',
    headers: { Authorization: 'Bearer ' + apiKey, 'Content-Type': 'application/json' },
    body: {
      content: original.caption_full || '',
      mediaItems: [{ url: videoUrl, type: 'video' }],
      platforms: [{ platform: 'tiktok', accountId }],
    },
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });
  const statusCode = response.statusCode || 0;
  const success = statusCode >= 200 && statusCode < 300;
  const result = {
    status: success ? 'TIKTOK_DRAFT_CREATED' : 'TIKTOK_PUBLISH_FAILED',
    processed_at: new Date().toISOString(),
    gdrive_file_id: fileId,
    gdrive_file_name: original.gdrive_file_name,
    gdrive_mime_type: original.gdrive_mime_type,
    video_url: videoUrl,
    content_angle: original.content_angle,
    caption: original.caption,
    hashtags: original.hashtags,
    caption_full: original.caption_full,
    zernio_status: statusCode,
    zernio_response: response.body,
  };

  if (success) {
    const statePath = original.state_path || '/files/state/wf05_manual_gdrive_processed.json';
    fs.mkdirSync(path.dirname(statePath), { recursive: true });
    let state = { processed: {} };
    if (fs.existsSync(statePath)) state = JSON.parse(fs.readFileSync(statePath, 'utf8'));
    if (!state.processed || typeof state.processed !== 'object') state.processed = {};
    state.processed[fileId] = result;
    const cutoff = Date.now() - (90 * 24 * 60 * 60 * 1000);
    for (const [key, val] of Object.entries(state.processed)) {
      if (val.status === 'TIKTOK_DRAFT_CREATED') {
        const ts = Date.parse(val.processed_at || '');
        if (Number.isFinite(ts) && ts < cutoff) delete state.processed[key];
      }
    }
    const tmpPath = statePath + '.tmp.' + process.pid;
    fs.writeFileSync(tmpPath, JSON.stringify(state, null, 2) + '\n', 'utf8');
    fs.renameSync(tmpPath, statePath);
  }
  output.push({ json: result });
}
return output;

return $input.all().map((item) => ({
  json: {
    status: 'WF05_CONFIG_REQUIRED',
    error: item.json.config_error || 'Konfigurasi WF-05 belum lengkap.',
  }
}));

const fs = require('fs');
const path = require('path');
const items = $input.all();
const output = [];

for (const item of items) {
  const d = item.json;
  const fileId = String(d.gdrive_file_id || '').trim();
  const statePath = d.state_path || '/files/state/wf05_manual_gdrive_processed.json';

  if (fileId) {
    try {
      let state = { processed: {} };
      if (fs.existsSync(statePath)) state = JSON.parse(fs.readFileSync(statePath, 'utf8'));
      if (state.processed && state.processed[fileId] && state.processed[fileId].status === 'IN_PROGRESS') {
        delete state.processed[fileId];
        const tmpPath = statePath + '.tmp.' + process.pid;
        fs.writeFileSync(tmpPath, JSON.stringify(state, null, 2) + '\n', 'utf8');
        fs.renameSync(tmpPath, statePath);
      }
    } catch (e) {}
  }

  output.push({
    json: {
      status: 'CAPTION_FAILED',
      gdrive_file_id: fileId,
      gdrive_file_name: d.gdrive_file_name,
      error: d.caption_error || 'Caption gagal dibuat.',
    }
  });
}
return output;

const apiKey = String($json.openai_api_key || '').trim();
if (!apiKey) {
  return [{ json: { ...$json, transcript_text: '', transcript_available: false, transcript_error: 'OpenAI API key tidak tersedia.' } }];
}

const items = $input.all();
const output = [];

for (const item of items) {
  const binaryData = item.binary?.data;
  if (!binaryData) {
    output.push({ json: { ...item.json, transcript_text: '', transcript_available: false, transcript_error: 'Binary video tidak ditemukan.' } });
    continue;
  }

  try {
    const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
    const boundary = '----FormBoundary' + Math.random().toString(36).slice(2);
    const fileName = item.json.gdrive_file_name || 'video.mp4';

    const formParts = [];
    formParts.push(
      '--' + boundary + '\r\n' +
      'Content-Disposition: form-data; name="file"; filename="' + fileName + '"\r\n' +
      'Content-Type: video/mp4\r\n\r\n'
    );
    formParts.push(buffer);
    formParts.push(
      '\r\n--' + boundary + '\r\n' +
      'Content-Disposition: form-data; name="model"\r\n\r\n' +
      'whisper-1'
    );
    formParts.push(
      '\r\n--' + boundary + '\r\n' +
      'Content-Disposition: form-data; name="language"\r\n\r\n' +
      'id'
    );
    formParts.push(
      '\r\n--' + boundary + '\r\n' +
      'Content-Disposition: form-data; name="response_format"\r\n\r\n' +
      'text'
    );
    formParts.push('\r\n--' + boundary + '--\r\n');

    const body = Buffer.concat(formParts.map(p => typeof p === 'string' ? Buffer.from(p) : p));

    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/audio/transcriptions',
      headers: {
        'Authorization': 'Bearer ' + apiKey,
        'Content-Type': 'multipart/form-data; boundary=' + boundary,
      },
      body,
      returnFullResponse: true,
      ignoreHttpStatusErrors: true,
    });

    const statusCode = response.statusCode || 0;
    const responseBody = typeof response.body === 'string' ? response.body : JSON.stringify(response.body || '');

    if (statusCode >= 200 && statusCode < 300) {
      const transcriptText = responseBody.trim();
      output.push({
        json: {
          ...item.json,
          transcript_text: transcriptText,
          transcript_available: transcriptText.length > 0,
          transcript_error: null,
        }
      });
    } else {
      output.push({
        json: {
          ...item.json,
          transcript_text: '',
          transcript_available: false,
          transcript_error: 'Whisper API error ' + statusCode + ': ' + responseBody.slice(0, 300),
        }
      });
    }
  } catch (error) {
    output.push({
      json: {
        ...item.json,
        transcript_text: '',
        transcript_available: false,
        transcript_error: 'Transcription failed: ' + (error.message || 'unknown error'),
      }
    });
  }
}

return output;
